const express = require('express');
const mysql = require('mysql2/promise');

const app = express();
app.use(express.json());

const pool = mysql.createPool({
  host: process.env.DB_HOST || 'localhost',
  user: process.env.DB_USER || 'app_user',
  password: process.env.DB_PASSWORD || '',
  database: process.env.DB_NAME || 'products_db',
  waitForConnections: true,
  connectionLimit: 10,
  queueLimit: 0
});

// Allowlist for sortable columns and sort directions
const ALLOWED_SORT_COLUMNS = ['name', 'price', 'created_at', 'id'];
const ALLOWED_SORT_DIRECTIONS = ['ASC', 'DESC'];

app.get('/api/products/search', async (req, res) => {
  try {
    const { name, sort_by, sort_dir, limit, offset } = req.query;

    if (!name || typeof name !== 'string' || name.trim().length === 0) {
      return res.status(400).json({ error: 'Query parameter "name" is required and must be a non-empty string.' });
    }

    // Validate and apply allowlist for sort column
    const sortColumn = ALLOWED_SORT_COLUMNS.includes(sort_by) ? sort_by : 'name';

    // Validate and apply allowlist for sort direction
    const sortDirection = ALLOWED_SORT_DIRECTIONS.includes((sort_dir || '').toUpperCase())
      ? (sort_dir).toUpperCase()
      : 'ASC';

    // Validate limit and offset as positive integers
    const parsedLimit = Math.min(Math.max(parseInt(limit, 10) || 20, 1), 100);
    const parsedOffset = Math.max(parseInt(offset, 10) || 0, 0);

    // Parameterized query — sort column and direction come from allowlists
    // and are interpolated as identifiers (not user-controlled strings).
    // The search term, limit, and offset are passed as bound parameters.
    const sql = `SELECT id, name, description, price, created_at
                 FROM products
                 WHERE name LIKE ?
                 ORDER BY \`${sortColumn}\` ${sortDirection}
                 LIMIT ? OFFSET ?`;

    const searchPattern = `%${name.trim()}%`;

    const [rows] = await pool.execute(sql, [searchPattern, String(parsedLimit), String(parsedOffset)]);

    return res.json({
      query: name.trim(),
      sort_by: sortColumn,
      sort_dir: sortDirection,
      limit: parsedLimit,
      offset: parsedOffset,
      count: rows.length,
      results: rows
    });
  } catch (err) {
    console.error('Search error:', err.message);
    return res.status(500).json({ error: 'Internal server error.' });
  }
});

const PORT = process.env.PORT || 3000;
